def nextPermutation(arr: Array[Int]): Boolean = {
    var i = arr.length - 2
    while (i >= 0 && arr(i) >= arr(i + 1)) {
        i -= 1
    }
    if (i < 0) {
        return false
    }
    var j = arr.length - 1
    while (arr(j) <= arr(i)) {
        j -= 1
    }
    val temp = arr(i)
    arr(i) = arr(j)
    arr(j) = temp
    var left = i + 1
    var right = arr.length - 1
    while (left < right) {
        val tmp = arr(left)
        arr(left) = arr(right)
        arr(right) = tmp
        left += 1
        right -= 1
    }
    true
}

