import scala.collection.mutable
import scala.collection.mutable.ListBuffer
import scala.math.BigInt

def solve(n: Long): Long = {
    if (n < 0) return -1
    val len0 = if (n == 0) 1 else n.toString.length

    val digits = (1 to 9).toArray
    val nBits = 9
    val maxBit = 1 << nBits
    val subsetsMap = mutable.Map[Int, ListBuffer[List[Int]]]()

    for (bit <- 1 until maxBit) {
        var s = 0
        val subset = ListBuffer[Int]()
        for (i <- 0 until nBits) {
            if ((bit & (1 << i)) != 0) {
                s += digits(i)
                subset += digits(i)
            }
        }
        if (s >= 1 && s <= 45) {
            subsetsMap.getOrElseUpdate(s, ListBuffer[List[Int]]()) += subset.toList
        }
    }

    var foundResult = false
    var result: Long = -1

    for (L <- len0 to 45 if !foundResult) {
        if (L > 19) {
            // Skip since beyond Long representation
        } else {
            val allSubsetsForL = subsetsMap.getOrElse(L, ListBuffer[List[Int]]())
            val filteredSubsets = 
                if (L % 2 == 0) {
                    allSubsetsForL.filter(_.forall(d => d % 2 == 0))
                } else {
                    allSubsetsForL.filter(set => set.count(d => d % 2 == 1) == 1)
                }
            var minCandidate = Long.MaxValue
            for (set <- filteredSubsets) {
                val halfLen = if (L % 2 == 0) L / 2 else (L - 1) / 2
                val multiset = ListBuffer[Int]()
                var center = -1
                var valid = true

                if (L % 2 == 0) {
                    for (d <- set) {
                        if (d % 2 != 0) {
                            valid = false
                        } else {
                            val count = d / 2
                            for (_ <- 0 until count) {
                                multiset += d
                            }
                        }
                    }
                } else {
                    var centerFound = false
                    for (d <- set) {
                        if (d % 2 == 1) {
                            if (centerFound) {
                                valid = false
                            } else {
                                centerFound = true
                                center = d
                                val count = (d - 1) / 2
                                for (_ <- 0 until count) {
                                    multiset += d
                                }
                            }
                        } else {
                            val count = d / 2
                            for (_ <- 0 until count) {
                                multiset += d
                            }
                        }
                    }
                    valid = valid && centerFound
                }
                if (valid && multiset.size == halfLen) {
                    val sortedMultiset = multiset.sorted
                    val firstHalfStr = sortedMultiset.mkString("")
                    val candStr = 
                        if (L % 2 == 0) {
                            firstHalfStr + firstHalfStr.reverse
                        } else {
                            firstHalfStr + center.toString + firstHalfStr.reverse
                        }
                    var candidateValue: Long = -1
                    try {
                        if (candStr.length <= 18) {
                            candidateValue = candStr.toLong
                        } else if (candStr.length == 19) {
                            val bigCand = BigInt(candStr)
                            if (bigCand <= Long.MaxValue) {
                                candidateValue = bigCand.toLong
                            } else {
                                candidateValue = -1
                            }
                        } else {
                            candidateValue = -1
                        }
                    } catch {
                        case _: Exception => candidateValue = -1
                    }
                    if (candidateValue != -1 && candidateValue > n) {
                        if (candidateValue < minCandidate) {
                            minCandidate = candidateValue
                        }
                    }
                }
            }
            if (minCandidate != Long.MaxValue) {
                foundResult = true
                result = minCandidate
            }
        }
    }
    if (foundResult) result else -1
}
